// HasProcessInstance applies the HasEdge predicate on the "process_instance" edge.
func HasProcessInstance() predicate.ProcessNodeInstance {
	return predicate.ProcessNodeInstance(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ProcessInstanceTable, ProcessInstanceColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasProcessInstanceWith applies the HasEdge predicate on the "process_instance" edge with a given conditions (other predicates).
func HasProcessInstanceWith(preds ...predicate.ProcessInstance) predicate.ProcessNodeInstance {
	return predicate.ProcessNodeInstance(func(s *sql.Selector) {
		step := newProcessInstanceStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ProcessNodeInstance) predicate.ProcessNodeInstance {
	return predicate.ProcessNodeInstance(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ProcessNodeInstance) predicate.ProcessNodeInstance {
	return predicate.ProcessNodeInstance(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ProcessNodeInstance) predicate.ProcessNodeInstance {
	return predicate.ProcessNodeInstance(sql.NotPredicates(p))
}
